class Solution {
public:
    int coinChange(vector<int>& c, int m) {
        if (m < 0) return -1;
        if (m == 0) return 0;
        if (c.size() == 0) return -1;
        int dp[m + 1];
        dp[0] = 0;
        for (int i = 1; i <= m; i++) {
            dp[i] = INT_MAX;
            for (int j = 0; j < c.size(); j++) {
                if (i >= c[j]) {
                    dp[i] = min(dp[i], dp[i - c[j]] + 1);
                }
            }
        }
        return dp[m] == INT_MAX ? -1 : dp[m];
    }
};

