class Solution:
    def coinChange(self, c, m) -> int:
        if m < 0:
            return -1
        if m == 0:
            return 0
        if not c:
            return -1
        dp = [float('inf')] * (m + 1)
        dp[0] = 0
        for i in range(1, m + 1):
            for j in range(len(c)):
                if i >= c[j]:
                    dp[i] = min(dp[i], dp[i - c[j]] + 1)
        return dp[m] if dp[m] != float('inf') else -1
